     1→import { useState, useEffect, useCallback } from "react";
     2→import { LoadingSpinner } from "@/components/ui/loading-spinner";
     3→import { Calendar as CalendarIcon, Clock as Clock, User as User, Wrench as Wrench, UserCheck as UserCheck, Pencil as Edit, Phone as Phone, Mail as Mail, Trash2 as Trash2 } from "lucide-react";
     4→import { Button } from "@/components/ui/button";
     5→import {
     6→  Dialog,
     7→  DialogBody,
     8→  DialogContent,
     9→  DialogDescription,
    10→  DialogFooter,
    11→  DialogHeader,
    12→  DialogTitle,
    13→} from "@/components/ui/dialog";
    14→import {
    15→  AlertDialog,
    16→  AlertDialogAction,
    17→  AlertDialogCancel,
    18→  AlertDialogContent,
    19→  AlertDialogDescription,
    20→  AlertDialogFooter,
    21→  AlertDialogHeader,
    22→  AlertDialogTitle,
    23→} from "@/components/ui/alert-dialog";
    24→import { Label } from "@/components/ui/label";
    25→import { Calendar as CalendarComponent } from "@/components/ui/calendar";
    26→import {
    27→  Popover,
    28→  PopoverContent,
    29→  PopoverTrigger,
    30→} from "@/components/ui/popover";
    31→import { SelectPopover } from "@/components/ui/select";
    32→import { Textarea } from "@/components/ui/textarea";
    33→import { format } from "date-fns";
    34→import { ptBR } from "date-fns/locale";
    35→import { cn } from "@/lib/utils";
    36→import { toast } from "sonner";
    37→import { useSelectedSalon } from "@/hooks/useSelectedSalon";
    38→import { appointmentService } from "@/services/appointmentService";
    39→import { userService } from "@/services/userService";
    40→import { serviceService } from "@/services/serviceService";
    41→import { clientService } from "@/services/clientService";
    42→import { agendaService } from "@/services/agendaService";
    43→import { Appointment } from "@/types/appointment";
    44→import { UserRole } from "@/types/user";
    45→import { convertLocalToUTC, formatUTCToLocal } from "@/utils/dateTimeHelpers";
    46→import { getUserDisplayName } from "@/utils/userHelpers";
    47→
    48→interface Professional {
    49→  id: string;
    50→  name: string;
    51→  nickname?: string;
    52→  workingHours?: Array<{
    53→    dayOfWeek?: string | number;
    54→    start: string;
    55→    end: string;
    56→    isOpen?: boolean;
    57→  }>;
    58→}
    59→
    60→interface Service {
    61→  id: string;
    62→  name: string;
    63→  duration: number;
    64→  price: number;
    65→}
    66→
    67→interface Client {
    68→  id: string;
    69→  name: string;
    70→  phone: string;
    71→  email?: string;
    72→}
    73→
    74→interface ModalEditarAgendamentoProps {
    75→  isOpen: boolean;
    76→  onClose: () => void;
    77→  appointment: Appointment | null;
    78→  onAppointmentUpdated: () => void;
    79→}
    80→
    81→
    82→export function ModalEditarAgendamento({
    83→  isOpen,
    84→  onClose,
    85→  appointment,
    86→  onAppointmentUpdated,
    87→}: ModalEditarAgendamentoProps) {
    88→  const { selectedSalon } = useSelectedSalon();
    89→  const [loading, setLoading] = useState(false);
    90→  const [loadingData, setLoadingData] = useState(true);
    91→  const [loadingHorarios, setLoadingHorarios] = useState(false);
    92→  const [isEditing, setIsEditing] = useState(false);
    93→  const [showCancelDialog, setShowCancelDialog] = useState(false);
    94→  const [cancelLoading, setCancelLoading] = useState(false);
    95→
    96→  // Função para verificar se o agendamento já passou considerando o timezone do salão
    97→  const isAppointmentPast = (): boolean => {
    98→    if (!appointment) return false;
    99→
   100→    try {
   101→      const appointmentTime = new Date(appointment.startTime);
   102→      const now = new Date();
   103→
   104→      // Se o salão tiver timezone configurado, usar para comparação mais precisa
   105→      // Por enquanto, fazemos comparação direta já que os horários estão em UTC
   106→      return appointmentTime < now;
   107→    } catch (error) {
   108→      console.error("Error checking appointment time:", error);
   109→      return false;
   110→    }
   111→  };
   112→
   113→  // Função para verificar se é uma reserva (quando clientName e serviceName são null/undefined)
   114→  const isReserva = (): boolean => {
   115→    if (!appointment) return false;
   116→
   117→    const clientName = (appointment as any).clientName || appointment.client?.name;
   118→    const serviceName = (appointment as any).serviceName || appointment.service?.name;
   119→
   120→    // É uma reserva quando ambos são nulos/undefined/vazios
   121→    return !clientName && !serviceName;
   122→  };
   123→
   124→  // Helper para formatar preço
   125→  const formatPrice = (price: any): string => {
   126→    if (typeof price === "number") {
   127→      return price.toFixed(2);
   128→    }
   129→    if (typeof price === "string") {
   130→      const numPrice = parseFloat(price);
   131→      return isNaN(numPrice) ? "0.00" : numPrice.toFixed(2);
   132→    }
   133→    return "0.00";
   134→  };
   135→
   136→  // Helper para converter data dd/MM/yyyy para yyyy-MM-dd (formato do input)
   137→  const formatDateForInput = (dateStr: string): string => {
   138→    if (!dateStr) return "";
   139→    const [day, month, year] = dateStr.split("/");
   140→    return `${year}-${month.padStart(2, "0")}-${day.padStart(2, "0")}`;
   141→  };
   142→
   143→  // Helper para converter data yyyy-MM-dd para dd/MM/yyyy (exibição)
   144→  const formatDateForDisplay = (dateStr: string): string => {
   145→    if (!dateStr) return "";
   146→    const [year, month, day] = dateStr.split("-");
   147→    return `${day}/${month}/${year}`;
   148→  };
   149→
   150→  // Estados para os dados do formulário
   151→  const [selectedClient, setSelectedClient] = useState<string>("");
   152→  const [selectedProfessional, setSelectedProfessional] = useState<string>("");
   153→  const [selectedService, setSelectedService] = useState<string>("");
   154→  const [selectedDate, setSelectedDate] = useState<string>("");
   155→  const [selectedTime, setSelectedTime] = useState<string>("");
   156→  const [notes, setNotes] = useState<string>("");
   157→
   158→  // Estados para os dados carregados
   159→  const [clients, setClients] = useState<Client[]>([]);
   160→  const [professionals, setProfessionals] = useState<Professional[]>([]);
   161→  const [services, setServices] = useState<Service[]>([]);
   162→  const [availableSlots, setAvailableSlots] = useState<string[]>([]);
   163→  const [salonWorkingHours, setSalonWorkingHours] = useState<{
   164→    start: string;
   165→    end: string;
   166→  } | null>(null);
   167→  const [salonOpeningHours, setSalonOpeningHours] = useState<any[]>([]);
   168→
   169→  // Estados para edição de horários (substituem selectedTime no modo edição)
   170→  const [editableStartTime, setEditableStartTime] = useState<string>("");
   171→  const [editableEndTime, setEditableEndTime] = useState<string>("");
   172→  const [editableDuration, setEditableDuration] = useState<number>(0);
   173→
   174→  // Opções para os dropdowns de horários
   175→  const [startTimeOptions, setStartTimeOptions] = useState<string[]>([]);
   176→  const [endTimeOptions, setEndTimeOptions] = useState<string[]>([]);
   177→  const [durationOptions, setDurationOptions] = useState<number[]>([]);
   178→
   179→  // Callbacks memoizados para evitar re-renderizações
   180→  const handleProfessionalSelect = useCallback((value: string) => {
   181→    setSelectedProfessional(value);
   182→  }, []);
   183→
   184→  const handleServiceSelect = useCallback((value: string) => {
   185→    setSelectedService(value);
   186→  }, []);
   187→
   188→  // Resetar formulário quando o modal abre/fecha
   189→  useEffect(() => {
   190→    if (isOpen && appointment) {
   191→      setLoadingData(false); // Não precisa carregar dados para o preview
   192→      // Carregar dados imediatamente para que estejam prontos para edição
   193→      if (selectedSalon?.id) {
   194→        loadInitialData();
   195→      }
   196→    } else {
   197→      resetForm();
   198→    }
   199→  }, [isOpen, appointment, selectedSalon?.id]);
   200→
   201→  const resetForm = () => {
   202→    setSelectedClient("");
   203→    setSelectedProfessional("");
   204→    setSelectedService("");
   205→    setSelectedDate("");
   206→    setSelectedTime("");
   207→    setNotes("");
   208→    setClients([]);
   209→    setProfessionals([]);
   210→    setServices([]);
   211→    setAvailableSlots([]);
   212→    setSalonWorkingHours(null);
   213→    setLoadingData(true);
   214→    setIsEditing(false);
   215→    // Limpar campos editáveis
   216→    setEditableStartTime("");
   217→    setEditableEndTime("");
   218→    setEditableDuration(0);
   219→    setStartTimeOptions([]);
   220→    setEndTimeOptions([]);
   221→    setDurationOptions([]);
   222→  };
   223→
   224→  // Gerar opções de horário de 15 em 15 minutos (00:00 - 23:45)
   225→  const generateTimeOptions = (): string[] => {
   226→    const options: string[] = [];
   227→    for (let hour = 0; hour < 24; hour++) {
   228→      for (let minute = 0; minute < 60; minute += 15) {
   229→        const time = `${hour.toString().padStart(2, "0")}:${minute.toString().padStart(2, "0")}`;
   230→        options.push(time);
   231→      }
   232→    }
   233→    return options;
   234→  };
   235→
   236→  // Gerar opções de duração: 15, 30, 45, 60, 90, 120, 150, 180, 240, 300, 360 minutos
   237→  const generateDurationOptions = (): number[] => {
   238→    return [15, 30, 45, 60, 90, 120, 150, 180, 240, 300, 360];
   239→  };
   240→
   241→  // Carregar horários disponíveis da API para os dropdowns editáveis
   242→  const loadEditableTimeSlots = useCallback(async (): Promise<void> => {
   243→    if (
   244→      !selectedProfessional ||
   245→      !selectedService ||
   246→      !selectedDate ||
   247→      !selectedSalon?.id
   248→    ) {
   249→      return;
   250→    }
   251→
   252→    try {
   253→      setLoadingHorarios(true);
   254→
   255→      // Buscar horários disponíveis da API
   256→      const response = await appointmentService.checkAvailability(
   257→        selectedDate,
   258→        selectedProfessional,
   259→        selectedService,
   260→        true // isEdit = true
   261→      );
   262→
   263→      const slotsFromAPI = Array.isArray(response)
   264→        ? response
   265→        : response.availableSlots || [];
   266→
   267→      if (slotsFromAPI.length > 0) {
   268→        const salonTimezone = selectedSalon?.timezone || "America/Sao_Paulo";
   269→
   270→        // Converter slots de ISO UTC para HH:mm no timezone do salão
   271→        const formattedSlots = slotsFromAPI.map((slot) => {
   272→          // Se o slot já está em formato HH:mm, manter
   273→          if (slot.match(/^\d{2}:\d{2}$/)) {
   274→            return slot;
   275→          }
   276→          // Se está em formato ISO (UTC), converter para o timezone do salão
   277→          return formatUTCToLocal(slot, salonTimezone, "HH:mm");
   278→        });
   279→
   280→        // Incluir o horário atual do agendamento como disponível
   281→        if (appointment) {
   282→          const currentStartTime = formatUTCToLocal(
   283→            appointment.startTime,
   284→            salonTimezone,
   285→            "HH:mm"
   286→          );
   287→          const currentEndTime = formatUTCToLocal(
   288→            appointment.endTime,
   289→            salonTimezone,
   290→            "HH:mm"
   291→          );
   292→
   293→          // Adicionar horário inicial atual se não estiver na lista
   294→          if (!formattedSlots.includes(currentStartTime)) {
   295→            formattedSlots.push(currentStartTime);
   296→          }
   297→
   298→          // Adicionar horário final atual se não estiver na lista
   299→          if (!formattedSlots.includes(currentEndTime)) {
   300→            formattedSlots.push(currentEndTime);
   301→          }
   302→
   303→          formattedSlots.sort();
   304→        }
   305→
   306→        // Atualizar opções dos dropdowns
   307→        setStartTimeOptions(formattedSlots);
   308→        setEndTimeOptions(formattedSlots);
   309→      } else {
   310→        // Fallback: usar horários mockados se API não retornar nada
   311→        setStartTimeOptions(generateTimeOptions());
   312→        setEndTimeOptions(generateTimeOptions());
   313→      }
   314→    } catch (error) {
   315→      console.error("Erro ao carregar horários disponíveis:", error);
   316→      // Fallback em caso de erro: usar horários mockados
   317→      setStartTimeOptions(generateTimeOptions());
   318→      setEndTimeOptions(generateTimeOptions());
   319→    } finally {
   320→      setLoadingHorarios(false);
   321→    }
   322→  }, [
   323→    selectedProfessional,
   324→    selectedService,
   325→    selectedDate,
   326→    selectedSalon?.id,
   327→    appointment,
   328→  ]);
   329→
   330→  const populateFormWithAppointment = () => {
   331→    if (!appointment) {
   332→      return;
   333→    }
   334→
   335→    const startTime = new Date(appointment.startTime);
   336→
   337→    const clientId = appointment.clientId || appointment.client?.id || "";
   338→    const professionalId =
   339→      appointment.professionalId || appointment.professional?.id || "";
   340→    const serviceId = appointment.serviceId || appointment.service?.id || "";
   341→
   342→    // Verificar se os IDs existem nas listas carregadas
   343→    const clientExists = clients.find((c) => c.id === clientId);
   344→    const professionalExists = professionals.find(
   345→      (p) => p.id === professionalId
   346→    );
   347→    const serviceExists = services.find((s) => s.id === serviceId);
   348→
   349→    // Popular os campos
   350→    setSelectedClient(clientId);
   351→    setSelectedProfessional(professionalId);
   352→    setSelectedService(serviceId);
   353→    setSelectedDate(format(startTime, "yyyy-MM-dd"));
   354→    setSelectedTime(format(startTime, "HH:mm"));
   355→    setNotes(appointment.notes || "");
   356→
   357→    // Popular horários editáveis para edição
   358→    const endTime = new Date(appointment.endTime);
   359→    setEditableStartTime(format(startTime, "HH:mm"));
   360→    setEditableEndTime(format(endTime, "HH:mm"));
   361→    setEditableDuration(appointment.duration || 60);
   362→
   363→    // Gerar opções de duração (mantém mockado)
   364→    setDurationOptions(generateDurationOptions());
   365→
   366→    // Carregar horários disponíveis da API (assíncrono)
   367→    loadEditableTimeSlots();
   368→  };
   369→
   370→  const loadInitialData = async () => {
   371→    if (!selectedSalon?.id) return;
   372→
   373→    try {
   374→      setLoadingData(true);
   375→
   376→      // Carregar clientes, profissionais e salão em paralelo
   377→      const [clientsResponse, professionalsResponse, salonResponse] =
   378→        await Promise.all([
   379→          clientService.getAll(),
   380→          userService.list({
   381→            role: UserRole.PROFESSIONAL,
   382→            salonId: selectedSalon.id,
   383→          }),
   384→          agendaService.getSalonOperatingHours(selectedSalon.id),
   385→        ]);
   386→
   387→      // Processar clientes
   388→      const clientsData = Array.isArray(clientsResponse)
   389→        ? clientsResponse
   390→        : (clientsResponse as any).data || [];
   391→      setClients(clientsData);
   392→
   393→      // Processar profissionais
   394→      const professionalsData = Array.isArray(professionalsResponse)
   395→        ? professionalsResponse
   396→        : professionalsResponse.data || [];
   397→      const processedProfessionals = professionalsData.map((prof: any) => {
   398→        return {
   399→          id: prof.id,
   400→          name: prof.name,
   401→          nickname: prof.nickname,
   402→          workingHours: prof.workingHours ||
   403→            prof.schedule || [{ start: "09:00", end: "18:00" }],
   404→        };
   405→      });
   406→      setProfessionals(processedProfessionals);
   407→
   408→      // Carregar todos os serviços do salão filtrados para reserva
   409→      const allServicesResponse = await serviceService.getBookableServices();
   410→      let allServices = [];
   411→      if (
   412→        allServicesResponse.customServices ||
   413→        allServicesResponse.standardServices
   414→      ) {
   415→        allServices = [
   416→          ...(allServicesResponse.customServices || []),
   417→          ...(allServicesResponse.standardServices || []),
   418→        ];
   419→      } else if (Array.isArray(allServicesResponse)) {
   420→        allServices = allServicesResponse;
   421→      }
   422→
   423→      // Remover duplicatas baseado no ID usando Map
   424→      const uniqueServicesMap = new Map();
   425→      allServices.forEach((service) => {
   426→        if (!uniqueServicesMap.has(service.id)) {
   427→          uniqueServicesMap.set(service.id, service);
   428→        }
   429→      });
   430→      const uniqueServices = Array.from(uniqueServicesMap.values());
   431→
   432→      setServices(uniqueServices);
   433→
   434→      // Processar horários do salão
   435→      if (
   436→        salonResponse &&
   437→        salonResponse.openingHours &&
   438→        salonResponse.openingHours.length > 0
   439→      ) {
   440→        // Salvar todos os horários para validação de datas
   441→        setSalonOpeningHours(salonResponse.openingHours);
   442→
   443→        // Pegar o primeiro horário encontrado como padrão
   444→        const firstOpenDay = salonResponse.openingHours.find(
   445→          (day) => day.isOpen
   446→        );
   447→        if (firstOpenDay) {
   448→          setSalonWorkingHours({
   449→            start: firstOpenDay.open || "09:00",
   450→            end: firstOpenDay.close || "18:00",
   451→          });
   452→        }
   453→      } else {
   454→        // Horário padrão se não conseguir carregar
   455→        setSalonWorkingHours({
   456→          start: "09:00",
   457→          end: "18:00",
   458→        });
   459→      }
   460→
   461→      // Popular o formulário agora que os dados estão carregados
   462→      if (appointment) {
   463→        // Forçar re-população depois que os estados foram atualizados
   464→        setTimeout(() => {
   465→          populateFormWithAppointment();
   466→        }, 200); // Delay maior para garantir que os estados foram atualizados
   467→      }
   468→    } catch (error) {
   469→      toast.error("Erro ao carregar dados necessários");
   470→    } finally {
   471→      setLoadingData(false);
   472→    }
   473→  };
   474→
   475→  // Carregar serviços quando profissional for selecionado (apenas durante edição ativa)
   476→  useEffect(() => {
   477→    if (isEditing && selectedProfessional && selectedSalon?.id) {
   478→      loadProfessionalServices(selectedProfessional);
   479→    }
   480→  }, [selectedProfessional, selectedSalon?.id, isEditing]);
   481→
   482→  // Popular formulário quando dados estão carregados e modal está aberto
   483→  useEffect(() => {
   484→    if (
   485→      isOpen &&
   486→      appointment &&
   487→      clients.length > 0 &&
   488→      professionals.length > 0 &&
   489→      services.length > 0 &&
   490→      !isEditing
   491→    ) {
   492→      populateFormWithAppointment();
   493→    }
   494→  }, [
   495→    isOpen,
   496→    appointment,
   497→    clients.length,
   498→    professionals.length,
   499→    services.length,
   500→    isEditing,
   501→  ]);
   502→
   503→  // Carregar horários disponíveis quando profissional, serviço ou data mudarem
   504→  useEffect(() => {
   505→    if (selectedProfessional && selectedService && selectedDate) {
   506→      loadAvailableSlots();
   507→    } else {
   508→      setAvailableSlots([]);
   509→    }
   510→  }, [selectedProfessional, selectedService, selectedDate]);
   511→
   512→  // Recarregar horários disponíveis para edição quando profissional, serviço ou data mudarem
   513→  useEffect(() => {
   514→    if (isEditing && selectedProfessional && selectedService && selectedDate) {
   515→      loadEditableTimeSlots();
   516→    }
   517→  }, [
   518→    isEditing,
   519→    selectedProfessional,
   520→    selectedService,
   521→    selectedDate,
   522→    loadEditableTimeSlots,
   523→  ]);
   524→
   525→  const loadProfessionalServices = async (professionalId: string) => {
   526→    try {
   527→      // Para edição, sempre mostrar todos os serviços ativos
   528→      // O usuário pode querer mudar o serviço para outro que o profissional não está vinculado
   529→      if (!selectedSalon?.id) return;
   530→
   531→      const response = await serviceService.getBookableServices();
   532→      let servicesData = [];
   533→      if (response.customServices || response.standardServices) {
   534→        servicesData = [
   535→          ...(response.customServices || []),
   536→          ...(response.standardServices || []),
   537→        ];
   538→      } else if (Array.isArray(response)) {
   539→        servicesData = response;
   540→      }
   541→      setServices(servicesData);
   542→    } catch (error) {
   543→      setServices([]);
   544→    }
   545→  };
   546→
   547→  const generateTimeSlots = (
   548→    startHour: string,
   549→    endHour: string,
   550→    interval: number = 15
   551→  ): string[] => {
   552→    const slots: string[] = [];
   553→    const [startH, startM] = startHour.split(":").map(Number);
   554→    const [endH, endM] = endHour.split(":").map(Number);
   555→
   556→    const startMinutes = startH * 60 + startM;
   557→    const endMinutes = endH * 60 + endM;
   558→
   559→    for (
   560→      let minutes = startMinutes;
   561→      minutes < endMinutes;
   562→      minutes += interval
   563→    ) {
   564→      const hours = Math.floor(minutes / 60);
   565→      const mins = minutes % 60;
   566→      slots.push(
   567→        `${hours.toString().padStart(2, "0")}:${mins
   568→          .toString()
   569→          .padStart(2, "0")}`
   570→      );
   571→    }
   572→
   573→    return slots;
   574→  };
   575→
   576→  const getProfessionalWorkingHours = (
   577→    professionalId: string,
   578→    date: string
   579→  ) => {
   580→    const professional = professionals.find((p) => p.id === professionalId);
   581→    if (
   582→      !professional ||
   583→      !professional.workingHours ||
   584→      !Array.isArray(professional.workingHours) ||
   585→      professional.workingHours.length === 0
   586→    ) {
   587→      return null;
   588→    }
   589→
   590→    const dayOfWeek = new Date(date).getDay();
   591→    const dayNames = [
   592→      "sunday",
   593→      "monday",
   594→      "tuesday",
   595→      "wednesday",
   596→      "thursday",
   597→      "friday",
   598→      "saturday",
   599→    ];
   600→    const dayName = dayNames[dayOfWeek];
   601→
   602→    // Procurar horário específico do profissional para o dia
   603→    const daySchedule = professional.workingHours.find(
   604→      (wh: any) => wh.dayOfWeek === dayName || wh.dayOfWeek === dayOfWeek
   605→    );
   606→
