   759→  // Handler: Quando HORÁRIO INICIAL mudar → Recalcula DURAÇÃO (mantém horário final)
   760→  const handleStartTimeChange = (newStartTime: string): void => {
   761→    setEditableStartTime(newStartTime);
   762→
   763→    if (!editableEndTime) return;
   764→
   765→    // Calcular nova duração baseada no novo horário inicial e horário final existente
   766→    const [startHour, startMinute] = newStartTime.split(":").map(Number);
   767→    const [endHour, endMinute] = editableEndTime.split(":").map(Number);
   768→
   769→    const startMinutes = startHour * 60 + startMinute;
   770→    const endMinutes = endHour * 60 + endMinute;
   771→
   772→    let newDuration = endMinutes - startMinutes;
   773→
   774→    // Se o horário final for menor que o inicial, assumir dia seguinte
   775→    if (newDuration <= 0) {
   776→      newDuration += 24 * 60; // Adicionar 24 horas em minutos
   777→    }
   778→
   779→    setEditableDuration(newDuration);
   780→  };
