   782→  // Handler: Quando DURAÇÃO mudar → Recalcula HORÁRIO FINAL (mantém horário inicial)
   783→  const handleDurationChange = (newDuration: number): void => {
   784→    setEditableDuration(newDuration);
   785→
   786→    if (!editableStartTime) return;
   787→
   788→    // Calcular novo horário final baseado no horário inicial e nova duração
   789→    const [startHour, startMinute] = editableStartTime.split(":").map(Number);
   790→    const startMinutes = startHour * 60 + startMinute;
   791→    const endMinutes = startMinutes + newDuration;
   792→
   793→    // Normalizar para 24h (pode passar da meia-noite)
   794→    const normalizedEndMinutes = endMinutes % (24 * 60);
   795→    const endHour = Math.floor(normalizedEndMinutes / 60);
   796→    const endMinute = normalizedEndMinutes % 60;
   797→
   798→    const newEndTime = `${endHour.toString().padStart(2, "0")}:${endMinute
   799→      .toString()
   800→      .padStart(2, "0")}`;
   801→
   802→    setEditableEndTime(newEndTime);
